// Voorbeeld van rapid prototyping controls
void Update() {
    HandleMovement();
    HandleMaskMechanics();
}

// Modulaire check voor unlockable movement
void Update() {
    if (Input.GetButtonDown("Jump")) {
        if (isGrounded) {
            Jump();
        } else if (hasUnlockedDoubleJump && !hasDoubleJumped) {
            DoubleJump();
        }
    }
}

// Voorbeeld: aansturen van de Unity Animator
void UpdateAnimator() {
    animator.SetFloat("Speed", rb.velocity.magnitude);
    animator.SetBool("IsGrounded", isGrounded);
    if(isDashing) {
        animator.SetTrigger("Dash");
    }
}

// Voorbeeld C++ setup in Unreal
void APlayerCharacter::SetupPlayerInputComponent(UInputComponent* PlayerInputComponent) {
    Super::SetupPlayerInputComponent(PlayerInputComponent);
    PlayerInputComponent->BindAction("Jump", IE_Pressed, this, &ACharacter::Jump);
}

// Voorbeeld van de Blast Zone velocity check
void ABlastZone::OnOverlapBegin(AActor* OtherActor) {
    if (ACharacter* Player = Cast<ACharacter>(OtherActor)) {
        float Velocity = Player->GetVelocity().Size();
        if (Velocity > KnockbackThreshold) {
            EliminatePlayer(Player);
        }
    }
}

